index 0000000..1234567 100644
--- /dev/null
+++ b/src/middleware/auth.ts
@@ -0,0 +1,45 @@
+import { verify } from 'jsonwebtoken';
+
+export interface AuthToken {
+  userId: string;
+  role: string;
+  exp: number;
+}
+
+export function validateToken(token: string): AuthToken | null {
+  try {
+    const secret = process.env.JWT_SECRET;
+    if (!secret) {
+      console.error('JWT_SECRET not configured');
+      return null;
+    }
+    const decoded = verify(token, secret) as AuthToken;
+    return decoded;
+  } catch {
+    return null;
+  }
+}
+
+export class AuthMiddleware {
+  private secret: string;
+
+  constructor(secret: string) {
+    this.secret = secret;
+  }
+
+  handle(req: Request): AuthToken | null {
+    const authHeader = req.headers.get('Authorization');
+    if (!authHeader?.startsWith('Bearer ')) return null;
+    const token = authHeader.slice(7);
+    return validateToken(token);
+  }
+}
diff --git a/src/routes/api.ts b/src/routes/api.ts
index 1111111..2222222 100644
--- a/src/routes/api.ts
+++ b/src/routes/api.ts
@@ -1,5 +1,12 @@
 import { Router } from './router';
+import { AuthMiddleware } from '../middleware/auth';
+
+const auth = new AuthMiddleware(process.env.JWT_SECRET ?? '');

 export function createRouter(): Router {
   const router = new Router();
+
+  router.use((req) => {
+    const token = auth.handle(req);
+    if (!token) throw new Error('Unauthorized');
+  });
+
   return router;
 }
